#define mk(x,y) make_pair(x,y)
#define inf 0x3f3f3f3f
using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
int n;
vector<pair<string, int>> a;
bool cmp(const pair<string, int> x,const pair<string, int> y)
{
	return ((x.first.size() != y.first.size()) ? (x.first.size() > y.first.size()) : (x.first > y.first));
}
int main(void)
{
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	n = read();
	for (int i = 1; i <= n; ++i)
	{
		pair<string, int> Temp = mk("", i);
		cin>>Temp.first;
		a.push_back(Temp);
	}
	sort(a.begin(), a.end(), cmp);
	cout << a.begin()->second << '\n' << a.begin()->first;
	return false;
}
